var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"오늘 새벽, 한 무리의 괴한이 다국적 군사 연구소를 습격한 사건이 벌어져 사회에 충격을 줬습니다.","JPN":"本日の明け方、身元不明の侵入者によって、\\n多国籍軍事研究所が襲撃される事件が発生しました。","ENG":"Early this morning, a group of armed suspects brazenly raided a multinational military research center.","TWN":"今天淩晨，一群恐怖分子襲擊了多國軍事研究所，該事件對整個社會造成了很大的衝擊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"현장의 기자 연결해 보겠습니다.","JPN":"現場の記者からです。","ENG":"Let's hear from our reporter on site.","TWN":"我們把鏡頭交給位在現場的記者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"지금 보고 계시는 곳은 습격을 받은 퓨처 앳 워 산하 군사기술 연구소입니다.","JPN":"こちらは、襲撃を受けたフューチャーアットウォー傘下の軍事技術研究所です。","ENG":"The military research facility attacked this morning belongs to an organization called Future at War.","TWN":"我們現在看到的是遭受襲擊的天啟兵器軍事技術研究所。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"보안 인력이 있었지만, 중화기를 앞세운 괴한들을 막기에는 역부족이었습니다.","JPN":"警備員がいましたが、重火器を持っていた侵入者を防ぐことはできませんでした。","ENG":"Although the facility had security personnel, they were unable to fend off the attackers, who used heavy weaponry.","TWN":"據我們瞭解，雖然當時現場有保全人員，但他們無法阻擋配備了重武器的恐怖分子。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"현지 시각 새벽 2시, 보안 설비를 차단하고 연구소에 침입한 괴한들은 보안 직원 7명을 살해한 뒤 연구소 전산실에 침입했습니다.","JPN":"現地時間で午前2時、セキュリティ設備を遮断して研究所に侵入した者たちは、\\n警備員7人を殺害し、研究所の電算室に入り込みました。","ENG":"At approximately 2 a.m., the assailants shut down the security system and infiltrated the facility. They murdered seven security guards before slipping into the main computing center here.","TWN":"當地時間淩晨2點，入侵的恐怖分子關閉安保系統後，殺害了7名職員，隨後進入研究所的電腦室。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"이들은 연구소에서 보관 중이던 기밀자료를 모처에 전송한 것으로 추정됩니다.","JPN":"彼らは研究所に保管されていた機密資料を、某所へ転送したと思われます。","ENG":"They appear to have downloaded top secret data kept at this facility and transmitted it to an unknown recipient.","TWN":"警方推測，恐怖分子的目的是將保管在研究所內的機密資料發送到某處。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"침입자들은 신고를 받고 출동한 경찰과의 교전 끝에 도주한 것으로 알려졌습니다.","JPN":"侵入者たちは通報を受けて出動した警察との交戦の末、逃走した模様です。","ENG":"The attackers fled the scene after a firefight with the police who responded to the 911 call.","TWN":"報告顯示，恐怖分子在與收到通報的員警交火後逃逸。"},"stage":{"bg":"CITY_TWILIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"한밤중에 난리도 아니었어요.","JPN":"真夜中に大騒ぎをしていました。","ENG":"It got all crazy in the middle of the night.","TWN":"大半夜鬧得可厲害了。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"대로 쪽에서 총소리에 뭐가 크게 터지는 소리까지 들렸는데, 무서워서 무슨 일인가 보지도 못하고......","JPN":"道路の方から銃声や爆弾音が聞こえたんですけど、\\n怖くて何が起きてるのか、確認することもできませんでした……","ENG":"I could hear guns firing and stuff exploding from the road, but I was too scared to see what it was about...","TWN":"路那邊傳來了槍聲和爆炸聲，但是我太害怕了不敢看……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"현지 경찰은 사건 자료를 관리국에 전달하고 결과가 나오기만을 기다린다는 입장을 내놓았습니다.","JPN":"現地の警察は、事件資料を管理局へ受け渡し、結果を待ってます。","ENG":"The local police submitted their findings to the Administration, and have not commented beyond saying they are awaiting the results of the investigation.","TWN":"當地警方宣佈將把案件資料轉交給管理局，等待調查結果。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이렇듯 경찰 측이 신중한 입장을 취하는 반면, 연구소 측은 이번 사건의 모 정부가 배후에 있다고 발언했습니다.","JPN":"警察が事件に対して慎重に対応している一方、研究所は今回の件に某政府が関わっていると発言しました。","ENG":"While the police remain quiet, the research center says a certain nation's government may have masterminded this incident.","TWN":"與採取慎重立場的警方相反，研究所方面則表示這次事件背後有政府參與。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이에 대해 국제 정치 평론가 분을 모시고 자세한 이야기를 나눠 보도록 하겠습니다.","JPN":"これについて、国際政治評論家の方から詳しい話を伺います。","ENG":"We have with us in the studio an expert on international politics to discuss this in further detail.","TWN":"我們邀請了國際政治評論家對此進行詳細討論。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"안녕하십니까, 교수님.","JPN":"よろしくお願いします、教授。","ENG":"Hello, professor.","TWN":"您好，教授。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"안녕하세요.","JPN":"よろしくお願いします。","ENG":"Hello.","TWN":"您好。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이번 사건 뒤에 정치적인 갈등이 숨어 있다고 논평해 주셨는데, 어떤 이유에서입니까?","JPN":"今回の事件には政治的な葛藤が隠されているとおっしゃっていましたが、\\nその理由を説明していただけますか？","ENG":"You've noted that there are hidden political motivations behind this incident. What makes you say that?","TWN":"您說這個事件背後存在政治糾紛，請問您這麼評價的原因是什麼？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워는 대 침식전에 필요한 여러 기술을 개발, 공유해 온 다국적 기관입니다.","JPN":"フューチャーアットウォーは、対侵食戦に必要な様々な技術を開発し、共有していた多国籍機関です。","ENG":"Future at War is a multinational organization that has been developing and shares many technologies required for our fight against Corruption from the Counterside.","TWN":"天啟兵器是為了對抗侵蝕體而開發、共用多種技術的跨國機構。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"관리국이 공개한 기술을 지금까지 가장 많이 재현해 낸 곳이죠.","JPN":"管理局が公開した技術を、今までもっとも多く再現した機関でもあります。","ENG":"It has been a leader in duplicating the technologies disclosed by the Administration thus far.","TWN":"這裡最大程度地再現了管理局公開的技術。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"문제는 병기를 증여해도 핵심 기술은 엄중히 관리하는데, 각국은 이 기술들이 향후 국방력 경쟁에 큰 영향을 끼칠 것으로 보고 있습니다.","JPN":"この機関は、兵器を渡すことがあってもコア技術は厳重に管理しています。\\n各国はこの技術が今後、防衛力競争に大きな影響を及ぼすと考えてます。","ENG":"The problem is, even if they share the weapon systems produced from their R&D, they are very wary of disclosing the core technology. The countries involved are concerned such technologies will lead to a new arms race.","TWN":"問題是就算他們提供了武器，武器的核心技術還是會受到嚴格管理。因此各國都認為，這些技術將對未來的國防競爭產生巨大的影響。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};